package eval

import (
	"sort"

	"github.com/cribbager/cribbager/internal/cribbage"
)

//go:generate go run cribtable_gen.go
//go:generate go run keepprob_gen.go

// CribEV returns the exact expected crib value (in points) of throwing the two
// cards a and b to the crib, under a uniform opponent and starter. It is an O(1)
// lookup into the precomputed table (cribtable.go, regenerated by
// cribtable_gen.go), so the discard evaluator is deterministic and needs no
// runtime sampling.
func CribEV(a, b cribbage.Card) float64 {
	lo, hi := int(a.Rank), int(b.Rank)
	if lo > hi {
		lo, hi = hi, lo
	}
	suited := 0
	if a.Suit == b.Suit && lo != hi {
		suited = 1
	}
	return cribEVTable[lo][hi][suited]
}

// RankedDiscard is one of the 15 holds with its expected-value breakdown: the
// exact expected hand value, the signed expected crib value, and their sum.
type RankedDiscard struct {
	Discard [2]cribbage.Card
	Keep    [4]cribbage.Card
	EHand   float64 // exact expected show value of the kept four
	Crib    float64 // expected crib value, signed (+ your crib, − opponent's)
	Score   float64 // EHand + Crib — what the discard maximizes
}

// RankDiscards scores all 15 holds best-first by exact expected hand value plus
// the signed exact expected crib value. It is the single source of truth for the
// discard decision and its explanation. Stable: ties keep enumeration order, so
// the top entry matches the brute-force argmax.
func RankDiscards(h [6]cribbage.Card, myCrib bool) []RankedDiscard {
	sign := -1.0
	if myCrib {
		sign = 1.0
	}
	discards, keeps := discardPairs(h)
	ranked := make([]RankedDiscard, len(discards))
	for idx := range discards {
		eHand := ExpectedHandValue(keeps[idx], h[:])
		crib := sign * CribEV(discards[idx][0], discards[idx][1])
		ranked[idx] = RankedDiscard{
			Discard: discards[idx],
			Keep:    keeps[idx],
			EHand:   eHand,
			Crib:    crib,
			Score:   eHand + crib,
		}
	}
	sort.SliceStable(ranked, func(i, j int) bool { return ranked[i].Score > ranked[j].Score })
	return ranked
}

// BestDiscardEV chooses the discard that maximizes the kept hand's exact expected
// value plus the exact expected crib value. This is the canonical bot's discard:
// fully deterministic (the crib term is an exact table lookup, not sampled).
func BestDiscardEV(h [6]cribbage.Card, myCrib bool) (discard [2]cribbage.Card, keep [4]cribbage.Card) {
	top := RankDiscards(h, myCrib)[0]
	return top.Discard, top.Keep
}
